package com.restaurantcraft.data;
public enum RestaurantLevel { ONE(1,6,2,4,3,100,0,0), TWO(2,9,4,16,6,200,100,30000), THREE(3,12,8,64,9,300,200,150000); public final int stars,range,tableLimit,chairLimit,recipeSlots,popularityCap,needPopularity,needMoney; RestaurantLevel(int s,int r,int t,int c,int rs,int pc,int np,int nm){stars=s;range=r;tableLimit=t;chairLimit=c;recipeSlots=rs;popularityCap=pc;needPopularity=np;needMoney=nm;} public RestaurantLevel next(){return this==ONE?TWO:this==TWO?THREE:THREE;} public static RestaurantLevel byStars(int s){return s>=3?THREE:s==2?TWO:ONE;} }
